import{_ as i,o as e,c as a,ai as t}from"./chunks/framework.CsYGeNYI.js";const r=JSON.parse('{"title":"后台 Exec 和 Process 工具","description":"","frontmatter":{"read_when":["添加或修改后台 exec 行为","调试长时间运行的 exec 任务"],"summary":"后台 exec 执行和进程管理","title":"后台 Exec 和 Process 工具","x-i18n":{"generated_at":"2026-02-03T10:05:51Z","model":"claude-opus-4-5","provider":"pi","source_hash":"e11a7d74a75000d6882f703693c2c49a2ecd3e730b6ec2b475ac402abde9e465","source_path":"gateway/background-process.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/background-process.md","filePath":"zh-CN/gateway/background-process.md","lastUpdated":null}'),l={name:"zh-CN/gateway/background-process.md"};function o(d,s,n,h,p,c){return e(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="后台-exec-process-工具" tabindex="-1"><a class="header-anchor" href="#后台-exec-process-工具">#</a> 后台 Exec + Process 工具</h1><p>OpenSoul 通过 <code>exec</code> 工具运行 shell 命令，并将长时间运行的任务保存在内存中。<code>process</code> 工具管理这些后台会话。</p><h2 id="exec-工具" tabindex="-1"><a class="header-anchor" href="#exec-工具">#</a> exec 工具</h2><p>关键参数：</p><ul><li><code>command</code>（必填）</li><li><code>yieldMs</code>（默认 10000）：在此延迟后自动转为后台运行</li><li><code>background</code>（布尔值）：立即转为后台运行</li><li><code>timeout</code>（秒，默认 1800）：在此超时后终止进程</li><li><code>elevated</code>（布尔值）：如果启用/允许提权模式，则在宿主机上运行</li><li>需要真实 TTY？设置 <code>pty: true</code>。</li><li><code>workdir</code>、<code>env</code></li></ul><p>行为：</p><ul><li>前台运行直接返回输出。</li><li>当转为后台运行（显式或超时）时，工具返回 <code>status: &quot;running&quot;</code> + <code>sessionId</code> 和一小段尾部输出。</li><li>输出保存在内存中，直到会话被轮询或清除。</li><li>如果 <code>process</code> 工具被禁用，<code>exec</code> 将同步运行并忽略 <code>yieldMs</code>/<code>background</code>。</li></ul><h2 id="子进程桥接" tabindex="-1"><a class="header-anchor" href="#子进程桥接">#</a> 子进程桥接</h2><p>当在 exec/process 工具之外生成长时间运行的子进程时（例如 CLI 重新生成或 Gateway 网关辅助程序），请附加子进程桥接辅助程序，以便终止信号被转发，监听器在退出/错误时被分离。这可以避免在 systemd 上产生孤立进程，并保持跨平台的关闭行为一致。</p><p>环境变量覆盖：</p><ul><li><code>PI_BASH_YIELD_MS</code>：默认 yield 时间（毫秒）</li><li><code>PI_BASH_MAX_OUTPUT_CHARS</code>：内存输出上限（字符）</li><li><code>OPENSOUL_BASH_PENDING_MAX_OUTPUT_CHARS</code>：每个流的待处理 stdout/stderr 上限（字符）</li><li><code>PI_BASH_JOB_TTL_MS</code>：已完成会话的 TTL（毫秒，限制在 1 分钟至 3 小时之间）</li></ul><p>配置（推荐）：</p><ul><li><code>tools.exec.backgroundMs</code>（默认 10000）</li><li><code>tools.exec.timeoutSec</code>（默认 1800）</li><li><code>tools.exec.cleanupMs</code>（默认 1800000）</li><li><code>tools.exec.notifyOnExit</code>（默认 true）：当后台 exec 退出时，将系统事件加入队列并请求心跳。</li></ul><h2 id="process-工具" tabindex="-1"><a class="header-anchor" href="#process-工具">#</a> process 工具</h2><p>操作：</p><ul><li><code>list</code>：正在运行和已完成的会话</li><li><code>poll</code>：获取会话的新输出（同时报告退出状态）</li><li><code>log</code>：读取聚合输出（支持 <code>offset</code> + <code>limit</code>）</li><li><code>write</code>：发送 stdin（<code>data</code>，可选 <code>eof</code>）</li><li><code>kill</code>：终止后台会话</li><li><code>clear</code>：从内存中移除已完成的会话</li><li><code>remove</code>：如果正在运行则终止，否则清除已完成的会话</li></ul><p>注意事项：</p><ul><li>只有后台会话会在内存中列出/保留。</li><li>会话在进程重启时会丢失（无磁盘持久化）。</li><li>会话日志只有在你运行 <code>process poll/log</code> 且工具结果被记录时才会保存到聊天历史。</li><li><code>process</code> 按智能体隔离；它只能看到该智能体启动的会话。</li><li><code>process list</code> 包含派生的 <code>name</code>（命令动词 + 目标）以便快速浏览。</li><li><code>process log</code> 使用基于行的 <code>offset</code>/<code>limit</code>（省略 <code>offset</code> 以获取最后 N 行）。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例">#</a> 示例</h2><p>运行长时间任务并稍后轮询：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;exec&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sleep 5 &amp;&amp; echo done&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;yieldMs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;process&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;poll&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sessionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;id&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>立即在后台启动：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;exec&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npm run build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;background&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>发送 stdin：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;process&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;write&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sessionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;id&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;y</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',26)])])}const E=i(l,[["render",o]]);export{r as __pageData,E as default};
